import{_ as o,o as a,c as t,a2 as s}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Demo Games","description":"Demo Games | Spinoko Theme","frontmatter":{"title":"Demo Games","description":"Demo Games | Spinoko Theme","weight":100,"extra":{"order":100},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/demo-games"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/demo-games"}],["meta",{"property":"og:title","content":"Demo Games"}],["meta",{"property":"og:description","content":"Demo Games | Spinoko Theme"}],["meta",{"name":"twitter:title","content":"Demo Games"}],["meta",{"name":"twitter:description","content":"Demo Games | Spinoko Theme"}]]},"headers":[],"relativePath":"docs/spinoko/demo-games.md","filePath":"docs/spinoko/demo-games.md"}'),i={name:"docs/spinoko/demo-games.md"};function n(r,e,l,m,d,c){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="demo-games" tabindex="-1">Demo Games <a class="header-anchor" href="#demo-games" aria-label="Permalink to &quot;Demo Games&quot;">​</a></h1><p>Many casino affiliates want to add demo versions of casino games to their websites. In this page you&#39;ll find the recommended way of doing it for Spinoko theme.</p><h3 id="spinoko-slots-launch" tabindex="-1">Spinoko + Slots Launch <a class="header-anchor" href="#spinoko-slots-launch" aria-label="Permalink to &quot;Spinoko + Slots Launch&quot;">​</a></h3><p><a href="https://dinomatic.com/refer/slotslaunch" target="_blank" rel="noreferrer">Slots Launch</a> provides an easy way for displaying demo games on your website. They have more than 17,000 games to choose from and a nice WordPress plugin to easily add those games.</p><p>The plugin integrates with Spinoko very nicely, and to make it even easier for you, I created a special child theme for Spinoko that you can install alongside the plugin. The child theme provides you with standard WordPress blocks that you can use instead of shortcodes. It also includes some styles to make the plugin sections look like part of the theme.</p><p>Here are a few easy steps that will allow you to display the demo games on your website:</p><ul><li>download the child theme from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a></li><li>install the child theme and activate it</li><li>sign up for an account at <a href="https://dinomatic.com/refer/slotslaunch" target="_blank" rel="noreferrer">slotslaunch.com</a> if you don&#39;t have one already</li><li>download and install the Slots Launch WP plugin</li><li>visit the plugin settings page and the setup wizard will take you through the process.</li></ul><p>Now you can add any demo game you want to your website using nice and easy-to-use WordPress blocks. You can also use blocks for &quot;Game Archive&quot; and &quot;Provider Archive&quot; shortcodes, and they will display a listing of games and game providers.</p><h3 id="demo" tabindex="-1">Demo <a class="header-anchor" href="#demo" aria-label="Permalink to &quot;Demo&quot;">​</a></h3><p>Check out Spinoko demo website for examples <a href="https://demos.dinomatic.com/kuala-lumpur/game/blood-suckers-ii/" target="_blank" rel="noreferrer">here</a> and <a href="https://demos.dinomatic.com/kuala-lumpur/game/blood-suckers/" target="_blank" rel="noreferrer">here</a>.</p>',10)])])}const u=o(i,[["render",n]]);export{p as __pageData,u as default};
